import io
import contextlib

def code_executor(code: str, timeout: int = 30) -> dict:
    stdout = io.StringIO()
    stderr = io.StringIO()
    result = None
    try:
        with contextlib.redirect_stdout(stdout), contextlib.redirect_stderr(stderr):
            exec_globals = {"__builtins__": __builtins__}
            exec(code, exec_globals)
            result = exec_globals.get("result", None)
    except Exception as e:
        return {"success": False, "error": str(e), "stdout": stdout.getvalue(), "stderr": stderr.getvalue()}
    return {"success": True, "result": result, "stdout": stdout.getvalue(), "stderr": stderr.getvalue()}
